arguments.file_text:
@page "/chat"
@layout ChatLayout
@using sv_bd45fd93d51d4f30a0abe2b79a794d15.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Team Chat</PageTitle>

<div class="chat-container">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@TruncateDescription(ch.Description)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(threadOpen ? "thread-visible" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <span class="channel-description">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="HandleScrollAsync">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-row" @onmouseover="() => hoveredMessageId = msg.Id"
                             @onmouseout="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                            <div class="message-bubble">
                                <div class="message-meta">
                                    <span class="author">@msg.Author</span>
                                    <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                                </div>
                                <div class="message-content">@msg.Content</div>

                                @if (msg.Reactions.Count > 0)
                                {
                                    <div class="reaction-row">
                                        @foreach (var r in msg.Reactions)
                                        {
                                            <span class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                  @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)">
                                                @r.Emoji @r.Users.Count
                                            </span>
                                        }
                                    </div>
                                }

                                @if (msg.ReplyToId is null && threadSummaries.TryGetValue(msg.Id, out var summary))
                                {
                                    <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                        @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    </button>
                                }
                            </div>

                            @if (hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" title="Reply in thread"
                                            @onclick="() => OpenThreadAsync(msg)">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" title="Add reaction"
                                                @onclick="() => ToggleEmojiPicker(msg.Id)">
                                            😊 React
                                        </button>
                                        @if (emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in commonEmojis)
                                                {
                                                    <button class="emoji-option"
                                                            @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" placeholder="Type a message…" @bind="newMessageText"
                          @onkeydown="HandleMainKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <div class="message-meta">
                    <span class="author">@threadRootMessage.Author</span>
                    <span class="timestamp">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                </div>
                <div class="message-content">@threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (threadReplies is not null)
                {
                    @foreach (var reply in threadReplies)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <span class="reaction-badge" title="@string.Join(", ", r.Users)">
                                            @r.Emoji @r.Users.Count
                                        </span>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" placeholder="Reply in thread…" @bind="threadReplyText"
                          @onkeydown="HandleThreadKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🔥", "👀"];

    // Data
    private List<Channel>? channels;
    private List<Message>? messages;
    private List<Message>? threadReplies;
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    // State
    private int activeChannelId;
    private Channel? activeChannel;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool threadOpen;
    private Message? threadRootMessage;
    private string newMessageText = "";
    private string threadReplyText = "";
    private int currentSkip;
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        currentSkip = 0;
        hasMoreMessages = true;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        currentSkip = messages.Count;
        await ChatService.MarkChannelReadAsync(channel.Id);
        BuildThreadSummaries();
        RefreshChannelUnread(channel.Id);
    }

    private void RefreshChannelUnread(int channelId)
    {
        if (channels is null) return;
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = channels[idx];
            channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        var rootIds = messages.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();

        foreach (var msg in messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value)))
        {
            var rootId = msg.ReplyToId!.Value;
            if (threadSummaries.TryGetValue(rootId, out var existing))
            {
                threadSummaries[rootId] = existing with
                {
                    ReplyCount = existing.ReplyCount + 1,
                    LastReplyAt = msg.SentAt > existing.LastReplyAt ? msg.SentAt : existing.LastReplyAt
                };
            }
            else
            {
                threadSummaries[rootId] = new ThreadSummary(rootId, 1, msg.SentAt);
            }
        }
    }

    private async Task HandleScrollAsync()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // Here we provide the mechanism; the actual scroll-position check
        // would require a small JS helper to detect scrollTop ≈ 0.
    }

    internal async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, currentSkip, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        if (older.Count > 0)
        {
            messages = [..older, ..(messages ?? [])];
            currentSkip += older.Count;
            BuildThreadSummaries();
        }

        isLoadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;
        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages ??= [];
        messages.Add(sent);
        currentSkip++;
        newMessageText = "";
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMsg)
    {
        threadRootMessage = rootMsg;
        threadOpen = true;
        threadReplyText = "";
        var all = await ChatService.GetThreadAsync(rootMsg.Id);
        threadReplies = all.Where(m => m.Id != rootMsg.Id).ToList();
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies ??= [];
        threadReplies.Add(reply);
        threadReplyText = "";

        // Update summary in main view
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
        {
            threadSummaries[threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }

        // Also add to main messages list so it appears there too
        messages?.Add(reply);
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Optimistically update the local message
        UpdateLocalReaction(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        UpdateLocalReaction(messageId, emoji);
    }

    private void UpdateLocalReaction(int messageId, string emoji)
    {
        var msg = messages?.FirstOrDefault(m => m.Id == messageId)
                  ?? threadReplies?.FirstOrDefault(m => m.Id == messageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length <= 40 ? description : string.Concat(description.AsSpan(0, 37), "...");
    }
}

