    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        currentSkip = 0;
        hasMoreMessages = true;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        currentSkip = messages.Count;
        await ChatService.MarkChannelReadAsync(channel.Id);
        BuildThreadSummaries();
        RefreshChannelUnread(channel.Id);
    }

    private void RefreshChannelUnread(int channelId)
    {
        if (channels is null) return;
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = channels[idx];
            channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        if (messages is null) return;

        var rootIds = messages.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();

        foreach (var msg in messages.Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value)))
        {
            var rootId = msg.ReplyToId!.Value;
            if (threadSummaries.TryGetValue(rootId, out var existing))
            {
                threadSummaries[rootId] = existing with
                {
                    ReplyCount = existing.ReplyCount + 1,
                    LastReplyAt = msg.SentAt > existing.LastReplyAt ? msg.SentAt : existing.LastReplyAt
                };
            }
            else
            {
                threadSummaries[rootId] = new ThreadSummary(rootId, 1, msg.SentAt);
            }
        }
    }

    private async Task HandleScrollAsync()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // Here we provide the mechanism; the actual scroll-position check
        // would require a small JS helper to detect scrollTop ≈ 0.
    }

    internal async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages || activeChannel is null) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, currentSkip, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        if (older.Count > 0)
        {
            messages = [..older, ..(messages ?? [])];
            currentSkip += older.Count;
            BuildThreadSummaries();
        }

        isLoadingMore = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;
        var sent = await ChatService.SendMessageAsync(activeChannel.Id, newMessageText.Trim(), null);
        messages ??= [];
        messages.Add(sent);
        currentSkip++;
        newMessageText = "";
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(Message rootMsg)
    {
        threadRootMessage = rootMsg;
        threadOpen = true;
        threadReplyText = "";
        var all = await ChatService.GetThreadAsync(rootMsg.Id);
        threadReplies = all.Where(m => m.Id != rootMsg.Id).ToList();
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies ??= [];
        threadReplies.Add(reply);
        threadReplyText = "";

        // Update summary in main view
        if (threadSummaries.TryGetValue(threadRootMessage.Id, out var existing))
        {
            threadSummaries[threadRootMessage.Id] = existing with
            {
                ReplyCount = existing.ReplyCount + 1,
                LastReplyAt = reply.SentAt
            };
        }
        else
        {
            threadSummaries[threadRootMessage.Id] = new ThreadSummary(threadRootMessage.Id, 1, reply.SentAt);
        }

        // Also add to main messages list so it appears there too
        messages?.Add(reply);
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Optimistically update the local message
        UpdateLocalReaction(messageId, emoji);
    }

    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        UpdateLocalReaction(messageId, emoji);
    }

    private void UpdateLocalReaction(int messageId, string emoji)
    {
        var msg = messages?.FirstOrDefault(m => m.Id == messageId)
                  ?? threadReplies?.FirstOrDefault(m => m.Id == messageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length <= 40 ? description : string.Concat(description.AsSpan(0, 37), "...");
    }
}
