toolArgs.file_text:
@page "/chat"
@layout ChatLayout
@using sv_bd45fd93d51d4f30a0abe2b79a794d15.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Team Chat</PageTitle>

<div class="chat-container">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (channels is not null)
            {
                @foreach (var ch in channels)
                {
                    <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(ch)">
                        <div class="channel-name"># @ch.Name</div>
                        <div class="channel-desc">@TruncateDescription(ch.Description)</div>
                        @if (ch.UnreadCount > 0)
                        {
                            <span class="unread-badge">@ch.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(threadOpen ? "thread-visible" : "")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h2># @activeChannel.Name</h2>
                <span class="channel-description">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="HandleScrollAsync">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (messages is not null)
                {
                    @foreach (var msg in messages)
                    {
                        <div class="message-row" @onmouseover="() => hoveredMessageId = msg.Id"
                             @onmouseout="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
